import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { gamesAPI, ordersAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';

interface Game {
  _id: string;
  title: string;
  description: string;
  price: number;
  platform: string;
  region: string;
  images: string[];
  availability: string;
  accountDetails: {
    username?: string;
    email?: string;
    additionalInfo?: string;
  };
}

const GameDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { state } = useAuth();
  const navigate = useNavigate();
  const [game, setGame] = useState<Game | null>(null);
  const [loading, setLoading] = useState(true);
  const [addingToCart, setAddingToCart] = useState(false);

  useEffect(() => {
    if (id) {
      fetchGame();
    }
  }, [id]);

  const fetchGame = async () => {
    try {
      setLoading(true);
      const response = await gamesAPI.getGame(id!);
      setGame(response.data);
    } catch (error) {
      console.error('Error fetching game:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAddToCart = async () => {
    if (!state.isAuthenticated) {
      navigate('/login');
      return;
    }

    if (!game) return;

    try {
      setAddingToCart(true);
      await ordersAPI.createOrder({
        games: [{ gameId: game._id }]
      });
      alert('Order placed successfully!');
      navigate('/');
    } catch (error: any) {
      alert(error.response?.data?.message || 'Error placing order');
    } finally {
      setAddingToCart(false);
    }
  };

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
        </div>
      </div>
    );
  }

  if (!game) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-gray-900 mb-4">Game Not Found</h1>
          <Link to="/" className="text-indigo-600 hover:text-indigo-800">
            Back to Home
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="bg-white rounded-lg shadow-lg overflow-hidden">
        <div className="grid grid-cols-1 lg:grid-cols-2">
          {/* Images */}
          <div className="p-6">
            {game.images.length > 0 ? (
              <img
                src={game.images[0]}
                alt={game.title}
                className="w-full h-96 object-cover rounded-lg"
              />
            ) : (
              <div className="w-full h-96 bg-gray-200 rounded-lg flex items-center justify-center">
                <span className="text-gray-500">No Image Available</span>
              </div>
            )}

            {game.images.length > 1 && (
              <div className="grid grid-cols-4 gap-2 mt-4">
                {game.images.slice(1).map((image, index) => (
                  <img
                    key={index}
                    src={image}
                    alt={`${game.title} ${index + 2}`}
                    className="w-full h-20 object-cover rounded cursor-pointer hover:opacity-75"
                  />
                ))}
              </div>
            )}
          </div>

          {/* Details */}
          <div className="p-6">
            <h1 className="text-3xl font-bold text-gray-900 mb-4">{game.title}</h1>

            <div className="mb-6">
              <span className={`inline-block px-3 py-1 rounded-full text-sm font-medium ${
                game.availability === 'available' 
                  ? 'bg-green-100 text-green-800' 
                  : 'bg-red-100 text-red-800'
              }`}>
                {game.availability}
              </span>
            </div>

            <div className="text-3xl font-bold text-indigo-600 mb-6">${game.price}</div>

            <div className="grid grid-cols-2 gap-4 mb-6">
              <div>
                <h3 className="text-sm font-medium text-gray-500">Platform</h3>
                <p className="text-lg font-semibold">{game.platform}</p>
              </div>
              <div>
                <h3 className="text-sm font-medium text-gray-500">Region</h3>
                <p className="text-lg font-semibold">{game.region}</p>
              </div>
            </div>

            <div className="mb-6">
              <h3 className="text-lg font-semibold mb-2">Description</h3>
              <p className="text-gray-600">{game.description}</p>
            </div>

            {game.accountDetails && (
              <div className="mb-6">
                <h3 className="text-lg font-semibold mb-2">Account Details</h3>
                <div className="bg-gray-50 p-4 rounded-lg">
                  {game.accountDetails.username && (
                    <p className="mb-2"><strong>Username:</strong> {game.accountDetails.username}</p>
                  )}
                  {game.accountDetails.email && (
                    <p className="mb-2"><strong>Email:</strong> {game.accountDetails.email}</p>
                  )}
                  {game.accountDetails.additionalInfo && (
                    <p><strong>Additional Info:</strong> {game.accountDetails.additionalInfo}</p>
                  )}
                </div>
              </div>
            )}

            <button
              onClick={handleAddToCart}
              disabled={game.availability !== 'available' || addingToCart}
              className={`w-full py-3 px-6 rounded-lg font-medium ${
                game.availability !== 'available'
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                  : addingToCart
                  ? 'bg-gray-300 text-gray-500'
                  : 'bg-indigo-600 hover:bg-indigo-700 text-white'
              }`}
            >
              {addingToCart ? 'Processing...' : game.availability === 'available' ? 'Place Order' : 'Not Available'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GameDetail;
